package main
import (
    "fmt"
    "io/ioutil"
    "net/http"
    "os"
    "strings"
)
func main() {
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request){
        url := os.Getenv("URL")
        if len(url) == 0{
            fmt.Fprintf(w,"URL is required")
            return 
        }
        if !strings.HasPrefix(url,"http://"){
            fmt.Fprintf(w,"URL must start with http://")
            return 
        }
        resp, err := http.Get(url)
        if err != nil {
            fmt.Fprintf(w,"%v",err)
            return 
        }
        defer resp.Body.Close()
        bodyBytes, _ := ioutil.ReadAll(resp.Body)
        fmt.Fprint(w,"Response: ",string(bodyBytes))
    })
}